  ('promotion-6f0ba476-moex-00005', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '下列那些項目屬於投資性不動產？①目前尚未決定未來用途所持有之土地  ②以融資租賃方', '["企業所擁有，並以營業租賃出租之建築物", "意圖於正常營 業過程出售而目前正在進行建造或開發之不動產", "僅", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00006', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年1月1日發行面額$1,000,000，票面利率6%，5年期公司債，每年12月31日 付息，扣除交易成本後取得現金$920,000，有效利率8%。甲公司採攤銷後成本衡量該公司債。 甲公司在X3年1月1日以$765,000自公開市場買回面額$800,000公司債。甲公司買回公司 債之金融負債除列損益為多少？', '["金融負債除列損失$6,370", "金融負債除列損失$29,000", "金融負債除列利益$35,000", "金融負債除列利益$41,370"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00007', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司以傳統零售價法計算 X1 年期末存貨，X1 年期初存貨之成本為$58,000，零售價為 $68,000；X1年進貨成本為$250,000、零售價為$284,000；淨加價$6,140，亦有淨減價$3,500。 X1 年銷貨收入為$305,000，並為優惠員工而提供員工折扣$4,640。甲公司 X1 年期末存貨成 本為多少？', '["$38,700", "$39,082", "$39,248", "$46,680"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00008', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司販售自行車與衝浪板兩種商品。甲公司在X1年3月底盤點存貨，自行車及衝浪板成 本分別為$68,000 及$12,000，評估其淨變現價值分別為$72,000 及$11,000。截至 X1 年 6 月 底，此兩種存貨均未售出，自行車之淨變現價值為$66,000，衝浪板之淨變現價值為$13,000。 甲公司應用成本與淨變現價值孰低法時係採逐項比較法。若甲公司分別於3月底及6月底編 製第一季與第二季財報，下列敘述何者正確？', '["第一季應認列自行車評價利益$4,000", "第一季資產負債表之存貨為$80,000", "第二季應認列衝浪板存貨損失迴轉利益$2,000", "第二季資產負債表之存貨為$78,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00009', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司X2年度稅後淨利為$68,100，普通股加權平均流通在外股數為26,000股，普通股全年 平均股價為$50。另有10,000股、6%的累積特別股全年流通在外，每股面額$10。此外，甲公 司在X1年所發行的認股證可按每股$40認購其普通股5,000股，截至X2年底為止，認股證 之持有人均尚未執行。甲公司X2年度之稀釋每股盈餘應為多少？', '["$2.07", "$2.30", "$2.39", "$2.52"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00010', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初以$680,000購入設備，估計使用年限為5年，殘值$30,000，採直線法提列 折舊，後續衡量採成本模式。X3年底因市場發生大幅變化，甲公司預估該設備生產產品之銷 貨收入將大幅下降。X3年底，甲公司評估該設備之使用價值為$250,000，而若將該設備出售， 其公允價值為$260,000，處分成本為$40,000。甲公司在X3年應認列多少減損損失？', '["$30,000", "$40,000", "$52,000", "$70,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00011', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '爾武公司 X5 年度報表顯示流動資產項目僅有現金、應收帳款、存貨與預付費用四項，流動 負債為$300,000、流動比率為3、速動比率為2、存貨週轉率為4，已知期末存貨金額為期初 存貨金額之四倍、X5年銷貨成本為$740,000，求期末預付費用金額為多少？', '["$4,000", "$8,000", "$300,000", "$296,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00012', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年初以$3,500,000購入房屋，估計使用年限30年，殘值$200,000；X2年初購入 設備，成本為$820,000，估計使用年限9年，殘值$10,000。此兩類資產均採直線法提列折舊， 後續衡量採重估價模式。X3 年底，甲公司進行資產重估價，房屋與設備之公允價值分別為 $3,400,000、$620,000。若不考慮所得稅，甲公司就房屋及設備進行重估價對X3年度（底） 財務報表相關項目之影響，下列何者正確？', '["本期淨利增加$210,000", "其他權益增加$230,000", "股東權益增加$250,000", "房屋與設備之帳面金額為$3,810,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00013', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '下列那些項目應表達於綜合損益表之其他綜合損益？①透過其他綜合損益按公允價值衡量之', '["國外營運機構財務報表換算之兌換差額", "採用權益法之關聯企業損益之份額", "不動產重估增值", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('promotion-6f0ba476-moex-00014', 'promotion-6f0ba476', 'promotion-6f0ba476-moex-114-e0b1f2ed', 'sub-promotion-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年1月1日向乙銀行借款$800,000，借款利率8%，每年年底付息，X4年底到 期，該借款之有效利率亦為8%。X2年甲公司因經營不善，致使甲公司在X2年底無法依約支付 利息。X3年初甲公司與乙銀行進行債務協商，乙銀行同意修改借款條款，協商完成時市場利率 為10%。債務協商後借款條款調整為：㉑X2年積欠利息$64,000併入本金中，亦即借款本金變 更為$864,000；㉒借款利率降為6%；㉓到期日展延至X6年底。4期折現率6%、8%及10%之複 利現值因子與年金現值因子如下表所示。甲公司債務協商應認列之債務協商利益應為多少？ 6% 8% 10% 複利現值因子 0.7921 0.7350 0.6830 年金現值因子 3.4651 3.3120 3.1698', '["$0", "$12,160", "$57,266", "$109,566"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:28+00:00", "source_pdf_sha1": "7561ec0faf86", "answer_pdf_sha1": "707153d62c75", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "118", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "財稅行政"}'::jsonb, NULL)
